static void TrainModel(string csvPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
        csvPath, hasHeader: true, separatorChar: ',');

    // Map "Yes"/"No" → true/false Label column
    var labelMapping = mlContext.Transforms.Conversion.MapValue(
        "Label",
        new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false },
        "Churned");

    var pipeline = labelMapping
        .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
        .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
